#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    double x = *(double*)a;
    double y = *(double*)b;
    if (x > y) return -1;
    if (x < y) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        double denominations[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf", &denominations[i]);
        }
        qsort(denominations, N, sizeof(double), compare);
        printf("Case %d:\n", T + 1);
        while (M--) {
            double amount;
            scanf("%lf", &amount);
            printf("Scenario %d:\n", M + 1);
            for (int i = 0; i < N; i++) {
                int count = (int)(amount / denominations[i]);
                if (count > 0) {
                    printf("%.2f %d\n", denominations[i], count);
                    amount -= count * denominations[i];
                }
            }
        }
    }
    return 0;
}

