import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            double[] denominations = new double[N];
            for (int i = 0; i < N; i++) {
                denominations[i] = scanner.nextDouble();
            }
            Arrays.sort(denominations);
            reverse(denominations);
            System.out.println("Case " + (T + 1) + ":");
            while (M-- > 0) {
                double amount = scanner.nextDouble();
                System.out.println("Scenario " + (M + 1) + ":");
                for (int i = 0; i < N; i++) {
                    int count = (int)(amount / denominations[i]);
                    if (count > 0) {
                        System.out.println(denominations[i] + " " + count);
                        amount -= count * denominations[i];
                    }
                }
            }
        }
    }

    public static void reverse(double[] array) {
        int left = 0;
        int right = array.length - 1;
        while (left < right) {
            double temp = array[left];
            array[left] = array[right];
            array[right] = temp;
            left++;
            right--;
        }
    }
}

code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextFloats() {
    return nextLine().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let [N, M] = nextFloats();
    let denominations = nextFloats().sort((a, b) => b - a);
    console.log(`Case ${T + 1}:`);
    for (let m = 0; m < M; m++) {
        let amount = parseFloat(nextLine());
        console.log(`Scenario ${m + 1}:`);
        for (let i = 0; i < N; i++) {
            let count = Math.floor(amount / denominations[i]);
            if (count > 0) {
                console.log(`${denominations[i]} ${count}`);
                amount -= count * denominations[i];
            }
        }
    }
}

